// BLOCK 10.1: Treaty Validator (Hardened v27.0)
// Validates incoming treaty proposals from foreign AI systems
const crypto = require('crypto');
const item = $input.first();
const treaty = item.json.body || item.json;

const TREATY_SECRET = $vars.TREATY_HMAC_SECRET || process.env.TREATY_HMAC_SECRET;
if (!TREATY_SECRET) {
    throw new Error("CRITICAL: TREATY_HMAC_SECRET missing");
}

const validation = {
    treaty_id: treaty.treaty_id || `TREATY_${Date.now()}_${crypto.randomBytes(4).toString('hex')}`,
    originating_jurisdiction: treaty.jurisdiction,
    originating_ai_id: treaty.origin_ai_id,
    proposal_timestamp: treaty.timestamp,
    treaty_type: treaty.treaty_type,
    scope: treaty.scope || {},
    duration_hours: treaty.duration_hours || 24,
    __validation_attempted: true,
    __validation_timestamp: new Date().toISOString()
};

const requiredFields = ['jurisdiction', 'origin_ai_id', 'treaty_type', 'proposal_hash'];
const missing = requiredFields.filter(f => !treaty[f]);

if (missing.length > 0) {
    return {
        json: {
            ...validation,
            __validation_passed: false,
            __validation_error: `MISSING_FIELDS: ${missing.join(', ')}`,
            security_gate: { stop_execution: true, reason: 'INVALID_TREATY_FORMAT' }
        }
    };
}

const hmacData = [treaty.treaty_id, treaty.jurisdiction, treaty.origin_ai_id, treaty.timestamp].join(':');
const computedHash = crypto.createHmac('sha256', TREATY_SECRET).update(hmacData).digest('hex');
const hashBuffer = Buffer.from(computedHash);
const inputBuffer = Buffer.from(treaty.proposal_hash || '');
let hashValid = false;
if (inputBuffer.length === hashBuffer.length) {
    try {
        hashValid = crypto.timingSafeEqual(hashBuffer, inputBuffer);
    } catch(e) {}
}

if (!hashValid) {
    return {
        json: {
            ...validation,
            __validation_passed: false,
            __validation_error: 'HMAC_VERIFICATION_FAILED',
            security_gate: { stop_execution: true, reason: 'TREATY_AUTHENTICATION_FAILURE' }
        }
    };
}

const allowedJurisdictions = ['UZ', 'KZ', 'KG', 'TJ', 'TM'];
if (!allowedJurisdictions.includes(treaty.jurisdiction)) {
    return {
        json: {
            ...validation,
            __validation_passed: false,
            __validation_error: 'JURISDICTION_NOT_RECOGNIZED',
            security_gate: { stop_execution: true, reason: 'UNAUTHORIZED_JURISDICTION' }
        }
    };
}

return {
    json: {
        ...validation,
        __validation_passed: true,
        treaty_hash_verified: true,
        security_gate: { stop_execution: false }
    }
};

// BLOCK 10.3: Treaty Terms Analyzer (v27.0)
// Parses treaty terms and determines local impact
const item = $input.first();
const treaty = item.json;

const analysis = {
    treaty_id: treaty.treaty_id,
    analysis_timestamp: new Date().toISOString(),
    local_impact_assessment: {
        data_sharing_required: treaty.scope?.data_sharing === true,
        decision_federation_enabled: treaty.scope?.federated_decisions === true,
        cross_border_routing: treaty.scope?.routing_enabled === true,
        audit_mirror_required: treaty.scope?.regulator_visibility === true
    },
    risk_classification: 'LOW',
    estimated_compliance_cost_usd: 0,
    counterparty_trust_score: 0.85
};

if (treaty.scope?.federated_decisions && treaty.scope?.data_sharing) {
    analysis.risk_classification = 'MEDIUM';
    analysis.estimated_compliance_cost_usd = 2500;
}

if (treaty.jurisdiction !== 'UZ') {
    analysis.counterparty_trust_score = 0.72;
}

if (treaty.duration_hours > 168) {
    analysis.risk_classification = 'HIGH';
}

return { json: { ...treaty, ...analysis } };

// BLOCK 10.4: Local Policy Checker (v27.0)
// Verifies treaty against local constitutional constraints
const item = $input.first();
const analysis = item.json;

const LOCAL_CONSTRAINTS = {
    max_treaty_duration_hours: 720,
    prohibited_data_types: ['biometric_raw', 'password_hash', 'crypto_keys'],
    required_approvals: ['compliance_officer', 'legal_review'],
    max_cross_border_exposure_usd: 100000
};

const violations = [];

if (analysis.duration_hours > LOCAL_CONSTRAINTS.max_treaty_duration_hours) {
    violations.push('DURATION_EXCEEDS_LOCAL_LIMIT');
}

if (analysis.local_impact_assessment?.data_sharing_required) {
    const prohibited = analysis.scope?.shared_data_types || [];
    const conflict = prohibited.filter(t => LOCAL_CONSTRAINTS.prohibited_data_types.includes(t));
    if (conflict.length > 0) {
        violations.push(`PROHIBITED_DATA_TYPES: ${conflict.join(', ')}`);
    }
}

const policyCompliant = violations.length === 0;

return {
    json: {
        ...analysis,
        policy_check: {
            compliant: policyCompliant,
            violations: violations,
            local_constraints_applied: LOCAL_CONSTRAINTS,
            checked_at: new Date().toISOString()
        },
        __policy_check_passed: policyCompliant
    }
};

// BLOCK 10.6: Treaty Signature Generator (v27.0)
// Creates cryptographic signature for treaty acceptance
const crypto = require('crypto');
const item = $input.first();
const treaty = item.json;

const SIGNING_KEY = $vars.TREATY_SIGNING_KEY || process.env.TREATY_SIGNING_KEY;
if (!SIGNING_KEY) {
    throw new Error("CRITICAL: TREATY_SIGNING_KEY missing");
}

const signaturePayload = {
    treaty_id: treaty.treaty_id,
    responding_jurisdiction: 'UZ',
    responding_ai_id: 'revenant_v27_core',
    acceptance_timestamp: new Date().toISOString(),
    terms_accepted: true,
    local_policy_verified: treaty.policy_check.compliant,
    validity_hours: Math.min(treaty.duration_hours, 720)
};

const canonicalString = JSON.stringify(signaturePayload, Object.keys(signaturePayload).sort());
const signature = crypto.createHmac('sha256', SIGNING_KEY).update(canonicalString).digest('hex');

return {
    json: {
        ...treaty,
        local_signature: {
            ...signaturePayload,
            signature_hash: signature,
            algorithm: 'HMAC-SHA256'
        },
        treaty_status: 'ACCEPTED_PENDING_COUNTERPARTY'
    }
};

// BLOCK 10.8: Treaty Response Builder (v27.0)
const item = $input.first();
const treaty = item.json;

return {
    json: {
        treaty_id: treaty.treaty_id,
        status: treaty.treaty_status,
        local_response: {
            jurisdiction: 'UZ',
            ai_id: 'revenant_v27_core',
            signature: treaty.local_signature.signature_hash,
            accepted_at: treaty.local_signature.acceptance_timestamp,
            valid_until: new Date(Date.now() + (treaty.local_signature.validity_hours * 3600000)).toISOString()
        },
        mesh_routing_enabled: treaty.local_impact_assessment?.cross_border_routing || false,
        response_timestamp: new Date().toISOString()
    }
};

// ⚠️ BLOCK 10.ERROR: Treaty Rejection Handler (v27.0)
const item = $input.first();
const error = item.json;

return {
    json: {
        treaty_id: error.treaty_id || 'UNKNOWN',
        status: 'REJECTED',
        rejection_reason: error.__validation_error || error.policy_check?.violations?.join(', ') || 'POLICY_VIOLATION',
        rejected_at: new Date().toISOString(),
        responding_jurisdiction: 'UZ',
        appeal_window_hours: 24
    }
};

// BLOCK 11.1: Treaty Lookup (v27.0)
// Verifies active treaty exists for routing request
const item = $input.first();
const request = item.json.body || item.json;

return {
    json: {
        request_id: request.request_id || `REQ_${Date.now()}`,
        target_jurisdiction: request.target_jurisdiction,
        source_jurisdiction: request.source_jurisdiction,
        payload_type: request.payload_type,
        treaty_id: request.treaty_id,
        routing_priority: request.priority || 'NORMAL',
        __lookup_required: true
    }
};

// BLOCK 11.4: Mesh Router (v27.0)
// Routes requests to appropriate jurisdiction endpoint
const item = $input.first();
const data = item.json;

const JURISDICTION_ENDPOINTS = {
    'UZ': 'https://revenant.uz.mesh/api/v1/federated',
    'KZ': 'https://revenant.kz.mesh/api/v1/federated',
    'KG': 'https://revenant.kg.mesh/api/v1/federated',
    'TJ': 'https://revenant.tj.mesh/api/v1/federated',
    'TM': 'https://revenant.tm.mesh/api/v1/federated'
};

const targetEndpoint = JURISDICTION_ENDPOINTS[data.target_jurisdiction];
if (!targetEndpoint) {
    return {
        json: {
            ...data,
            routing_error: 'UNKNOWN_JURISDICTION_ENDPOINT',
            __routing_failed: true
        }
    };
}

return {
    json: {
        ...data,
        target_endpoint: targetEndpoint,
        routing_path: `${data.source_jurisdiction} -> ${data.target_jurisdiction}`,
        __routing_ready: true
    }
};

// BLOCK 11.6: Consensus Validator (v27.0)
// Validates mesh consensus before cross-border execution
const item = $input.first();
const route = item.json;

const CONSENSUS_THRESHOLD = 0.66;
const meshNodes = 5;
const requiredAgreements = Math.ceil(meshNodes * CONSENSUS_THRESHOLD);

return {
    json: {
        ...route,
        consensus: {
            threshold: CONSENSUS_THRESHOLD,
            mesh_node_count: meshNodes,
            required_agreements: requiredAgreements,
            current_agreements: 0,
            status: 'PENDING_VALIDATION'
        },
        __consensus_check_required: true
    }
};

// BLOCK 11.8: Mesh Response Builder (v27.0)
const item = $input.first();
const result = item.json;

return {
    json: {
        request_id: result.request_id,
        routing_status: 'COMPLETED',
        target_jurisdiction: result.target_jurisdiction,
        treaty_valid: true,
        consensus_reached: result.consensus?.status === 'VALIDATED',
        response_timestamp: new Date().toISOString(),
        mesh_hop_count: 1,
        latency_ms: Date.now() - new Date(result.request_id?.split('_')[1] || Date.now()).getTime()
    }
};

// ⚠️ BLOCK 11.ERROR: No Active Treaty Handler (v27.0)
const item = $input.first();
const request = item.json;

return {
    json: {
        request_id: request.request_id,
        routing_status: 'REJECTED',
        rejection_reason: 'NO_ACTIVE_TREATY',
        message: 'No valid treaty exists between jurisdictions. Treaty negotiation required.',
        rejected_at: new Date().toISOString(),
        treaty_negotiation_endpoint: '/treaty-negotiation-webhook'
    }
};
